import React from 'react'
import styled from 'styled-components'

const CheckboxWrapper = styled.div `
display:flex;
align-items:center;
margin:4px 0;
`

const DepartmentTitle = styled.span `
font-size:0.8rem;
`

const Check = styled.input `
text-align:center;
`


export default function Checkbox ({handleCheckboxChange, value}) {
	const handleChecked = () => {
		handleCheckboxChange()
	}
	return (
			<label><CheckboxWrapper><Check type='checkbox'value={value} onClick={handleChecked}/><DepartmentTitle>{value.name}</DepartmentTitle></CheckboxWrapper></label>

	)
}
